import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export default function ThreeBackground({ variant = 'cinema' }) {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, mount.clientWidth / mount.clientHeight, 0.1, 1000);
    camera.position.z = 5;

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setSize(mount.clientWidth, mount.clientHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    let animId;
    const objects = [];

    // ─── VARIANT: CINEMA (default) ─────────────────────────────────────────
    // Floating film strip frames, spinning reel, drifting dust particles,
    // two sweeping golden spotlight cones.
    if (variant === 'cinema') {

      // Ambient + colored lights
      scene.add(new THREE.AmbientLight(0xffffff, 0.25));
      const gold = new THREE.PointLight(0xffd700, 2.5, 30);
      gold.position.set(-6, 4, 4);
      scene.add(gold);
      const crimson = new THREE.PointLight(0xff2244, 1.8, 25);
      crimson.position.set(6, -3, 4);
      scene.add(crimson);

      // ── Film strip frames (flat planes with wireframe border) ──
      const frameCount = 18;
      for (let i = 0; i < frameCount; i++) {
        const w = 0.55 + Math.random() * 0.25;
        const h = w * 0.75;
        const geo = new THREE.PlaneGeometry(w, h);
        const mat = new THREE.MeshStandardMaterial({
          color: 0x1a1a2e,
          emissive: 0x0d0d1a,
          metalness: 0.5,
          roughness: 0.4,
          transparent: true,
          opacity: 0.55,
        });
        const frame = new THREE.Mesh(geo, mat);

        // Wireframe border overlay
        const edgeGeo = new THREE.EdgesGeometry(geo);
        const edgeMat = new THREE.LineBasicMaterial({
          color: Math.random() > 0.5 ? 0xffd700 : 0xff2244,
          transparent: true,
          opacity: 0.7,
        });
        const edges = new THREE.LineSegments(edgeGeo, edgeMat);
        frame.add(edges);

        frame.position.set(
          (Math.random() - 0.5) * 20,
          (Math.random() - 0.5) * 14,
          (Math.random() - 0.5) * 6 - 2
        );
        frame.rotation.z = (Math.random() - 0.5) * 0.6;
        frame.userData = {
          vx: (Math.random() - 0.5) * 0.004,
          vy: (Math.random() - 0.5) * 0.004,
          vz: (Math.random() - 0.5) * 0.002,
          rz: (Math.random() - 0.5) * 0.004,
        };
        scene.add(frame);
        objects.push({ mesh: frame, type: 'frame' });
      }

      // ── Film reel rings ──
      const reelColors = [0xffd700, 0xff2244, 0xcccccc];
      for (let i = 0; i < 3; i++) {
        const geo = new THREE.TorusGeometry(1.2 + i * 0.55, 0.035, 10, 80);
        const mat = new THREE.MeshStandardMaterial({
          color: reelColors[i],
          emissive: reelColors[i],
          emissiveIntensity: 0.3,
          metalness: 0.9,
          roughness: 0.15,
          transparent: true,
          opacity: 0.55,
        });
        const ring = new THREE.Mesh(geo, mat);
        ring.rotation.x = Math.PI / 5 + i * 0.4;
        ring.rotation.y = i * 0.6;
        scene.add(ring);
        objects.push({ mesh: ring, type: 'ring', speed: 0.003 + i * 0.0015 });
      }

      // ── Sprocket hole dots along two horizontal tracks ──
      for (let track = 0; track < 2; track++) {
        for (let j = 0; j < 20; j++) {
          const geo = new THREE.CircleGeometry(0.03, 8);
          const mat = new THREE.MeshBasicMaterial({
            color: 0xffd700,
            transparent: true,
            opacity: 0.35,
          });
          const dot = new THREE.Mesh(geo, mat);
          dot.position.set(
            -9 + j * 0.95,
            track === 0 ? 3.2 : -3.2,
            -1.5
          );
          scene.add(dot);
        }
      }

      // ── Dust / particle field ──
      const dustGeo = new THREE.BufferGeometry();
      const dustCount = 800;
      const dustPos = new Float32Array(dustCount * 3);
      const dustAlpha = new Float32Array(dustCount);
      for (let i = 0; i < dustCount; i++) {
        dustPos[i * 3]     = (Math.random() - 0.5) * 24;
        dustPos[i * 3 + 1] = (Math.random() - 0.5) * 16;
        dustPos[i * 3 + 2] = (Math.random() - 0.5) * 10 - 2;
        dustAlpha[i] = Math.random();
      }
      dustGeo.setAttribute('position', new THREE.BufferAttribute(dustPos, 3));
      const dustMat = new THREE.PointsMaterial({
        size: 0.025,
        color: 0xffeebb,
        transparent: true,
        opacity: 0.35,
      });
      const dust = new THREE.Points(dustGeo, dustMat);
      scene.add(dust);

      // ── Spotlight cones (two triangular planes sweeping) ──
      const makeSpotlight = (colorHex, startAngle) => {
        const spotGeo = new THREE.ConeGeometry(2.5, 8, 6, 1, true);
        const spotMat = new THREE.MeshBasicMaterial({
          color: colorHex,
          transparent: true,
          opacity: 0.045,
          side: THREE.DoubleSide,
          depthWrite: false,
        });
        const cone = new THREE.Mesh(spotGeo, spotMat);
        cone.position.set(startAngle > 0 ? -7 : 7, 6, -3);
        cone.rotation.x = Math.PI / 2;
        scene.add(cone);
        return { mesh: cone, type: 'spot', angle: startAngle };
      };
      objects.push(makeSpotlight(0xfff5cc, 1));
      objects.push(makeSpotlight(0xffd0d0, -1));

      // ── Mouse parallax ──
      const mouse = { x: 0, y: 0 };
      const onMouse = (e) => {
        mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
        mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;
      };
      window.addEventListener('mousemove', onMouse);

      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.01;

        objects.forEach((obj) => {
          if (obj.type === 'frame') {
            const m = obj.mesh;
            m.position.x += m.userData.vx;
            m.position.y += m.userData.vy;
            m.rotation.z += m.userData.rz;
            if (Math.abs(m.position.x) > 11) m.userData.vx *= -1;
            if (Math.abs(m.position.y) > 8)  m.userData.vy *= -1;
          }
          if (obj.type === 'ring') {
            obj.mesh.rotation.x += obj.speed * 0.7;
            obj.mesh.rotation.y += obj.speed;
          }
          if (obj.type === 'spot') {
            obj.mesh.rotation.z = Math.sin(t * 0.4 + obj.angle) * 0.5;
            obj.mesh.position.x = Math.sin(t * 0.3 + obj.angle) * 3;
          }
        });

        // Drift dust slowly upward
        const dp = dustGeo.attributes.position.array;
        for (let i = 0; i < dustCount; i++) {
          dp[i * 3 + 1] += 0.002;
          if (dp[i * 3 + 1] > 8) dp[i * 3 + 1] = -8;
        }
        dustGeo.attributes.position.needsUpdate = true;

        // Animate lights
        gold.position.x   = Math.sin(t * 0.4) * 6;
        gold.position.y   = Math.cos(t * 0.3) * 3 + 2;
        crimson.position.x = -Math.sin(t * 0.35) * 6;

        // Camera parallax
        camera.position.x += (mouse.x * 0.4 - camera.position.x) * 0.04;
        camera.position.y += (mouse.y * 0.25 - camera.position.y) * 0.04;
        camera.lookAt(0, 0, 0);

        renderer.render(scene, camera);
      };
      animate();

      const cleanup = () => window.removeEventListener('mousemove', onMouse);
      mount._cleanupMouse = cleanup;
    }

    // ─── VARIANT: PROJECTOR ────────────────────────────────────────────────
    // A dramatic single-beam projector effect: dense golden-white light shaft,
    // swirling dust motes, faint screen glow at the far end.
    if (variant === 'projector') {
      scene.add(new THREE.AmbientLight(0xffffff, 0.1));

      // Beam (layered translucent cones)
      for (let layer = 0; layer < 4; layer++) {
        const coneGeo = new THREE.ConeGeometry(0.12 + layer * 0.08, 12, 6, 1, true);
        const coneMat = new THREE.MeshBasicMaterial({
          color: 0xfff5d0,
          transparent: true,
          opacity: 0.06 - layer * 0.01,
          side: THREE.DoubleSide,
          depthWrite: false,
        });
        const cone = new THREE.Mesh(coneGeo, coneMat);
        cone.position.set(0, 3, -1);
        cone.rotation.x = Math.PI * 0.48;
        scene.add(cone);
      }

      // Screen glow plane
      const screenGeo = new THREE.PlaneGeometry(6, 3.5);
      const screenMat = new THREE.MeshBasicMaterial({
        color: 0xfff8e8,
        transparent: true,
        opacity: 0.04,
      });
      const screen = new THREE.Mesh(screenGeo, screenMat);
      screen.position.set(0, -3, -4);
      scene.add(screen);

      // Dust motes in beam
      const moteGeo = new THREE.BufferGeometry();
      const moteCount = 600;
      const motePos = new Float32Array(moteCount * 3);
      for (let i = 0; i < moteCount; i++) {
        const along = Math.random(); // 0-1 along beam
        const spread = along * 1.2;
        motePos[i * 3]     = (Math.random() - 0.5) * spread;
        motePos[i * 3 + 1] = 3 - along * 6;
        motePos[i * 3 + 2] = -1 - along * 4 + (Math.random() - 0.5) * spread;
      }
      moteGeo.setAttribute('position', new THREE.BufferAttribute(motePos, 3));
      const moteMat = new THREE.PointsMaterial({
        size: 0.018,
        color: 0xfff5cc,
        transparent: true,
        opacity: 0.7,
      });
      const motes = new THREE.Points(moteGeo, moteMat);
      scene.add(motes);

      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.008;
        const mp = moteGeo.attributes.position.array;
        for (let i = 0; i < moteCount; i++) {
          mp[i * 3]     += Math.sin(t + i) * 0.0005;
          mp[i * 3 + 1] -= 0.003;
          if (mp[i * 3 + 1] < -4) {
            const along = Math.random();
            const spread = along * 1.2;
            mp[i * 3]     = (Math.random() - 0.5) * spread;
            mp[i * 3 + 1] = 3;
            mp[i * 3 + 2] = -1 - along * 4;
          }
        }
        moteGeo.attributes.position.needsUpdate = true;
        renderer.render(scene, camera);
      };
      animate();
    }

    // ─── VARIANT: POPCORN ─────────────────────────────────────────────────
    // Cheerful rising shapes (tiny spheres, mini cubes) in warm cinema red &
    // golden yellow, like popcorn bursting upward.
    if (variant === 'popcorn') {
      scene.add(new THREE.AmbientLight(0xffffff, 0.4));
      const warm = new THREE.PointLight(0xff6622, 3, 20);
      warm.position.set(0, 2, 4);
      scene.add(warm);

      const kernelCount = 60;
      for (let i = 0; i < kernelCount; i++) {
        const isSphere = Math.random() > 0.45;
        const size = 0.06 + Math.random() * 0.12;
        const geo = isSphere
          ? new THREE.SphereGeometry(size, 8, 8)
          : new THREE.IcosahedronGeometry(size, 0);
        const mat = new THREE.MeshStandardMaterial({
          color: Math.random() > 0.5 ? 0xffd700 : 0xff3322,
          emissive: Math.random() > 0.5 ? 0x442200 : 0x330000,
          metalness: 0.2,
          roughness: 0.7,
          transparent: true,
          opacity: 0.75,
        });
        const kernel = new THREE.Mesh(geo, mat);
        kernel.position.set(
          (Math.random() - 0.5) * 14,
          (Math.random() - 0.5) * 10 - 5,
          (Math.random() - 0.5) * 4
        );
        kernel.userData = {
          vy: 0.012 + Math.random() * 0.018,
          vx: (Math.random() - 0.5) * 0.005,
          rx: (Math.random() - 0.5) * 0.03,
          ry: (Math.random() - 0.5) * 0.03,
          startY: -7 - Math.random() * 5,
          resetY: 8 + Math.random() * 3,
        };
        scene.add(kernel);
        objects.push({ mesh: kernel, type: 'kernel' });
      }

      let t = 0;
      const animate = () => {
        animId = requestAnimationFrame(animate);
        t += 0.01;
        objects.forEach((obj) => {
          const m = obj.mesh;
          m.position.y += m.userData.vy;
          m.position.x += m.userData.vx;
          m.rotation.x += m.userData.rx;
          m.rotation.y += m.userData.ry;
          if (m.position.y > m.userData.resetY) {
            m.position.y = m.userData.startY;
            m.position.x = (Math.random() - 0.5) * 14;
          }
        });
        warm.position.x = Math.sin(t * 0.5) * 4;
        renderer.render(scene, camera);
      };
      animate();
    }

    // ─── SHARED: resize handler ────────────────────────────────────────────
    const handleResize = () => {
      if (!mount) return;
      camera.aspect = mount.clientWidth / mount.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(mount.clientWidth, mount.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', handleResize);
      if (mount._cleanupMouse) mount._cleanupMouse();
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, [variant]);

  return (
    <div
      ref={mountRef}
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100%',
        height: '100%',
        zIndex: 0,
        pointerEvents: 'none',
      }}
    />
  );
}
